"                                        value="1"                                        @checked(old('validity_period', $procedure->validity_period))                                    >                                    <span>Controle por Período</span>                                </label>                                <span class="validity-helper">                                    Use para procedimentos recorrentes por tempo, em dias.                                </span>                            </div>                            <div class="form-group mb-0">                                <label>Intervalo em dias</label>                                <input                                    type="number"                                    name="interval_days"                                    id="intervalDays"                                    class="form-input @error('interval_days') input-invalid @enderror"                                    value="{{ old('interval_days', $procedure->interval_days) }}"                                    min="0"                                    step="1"                                >                                                                <small                                    class="form-error"                                    id="intervalDaysError"                                    style="display:none;"                                >                                    Informe o intervalo em dias.                                </small>                            </div>                        </div>                    </div>                </div>                <div class="procedure-section">                    <div class="procedure-section-header with-action">                        <div>                            <h3>Campos do procedimento</h3>                            <p class="sub-procedure">Adicione ou aj