="form-group field-col-name">                                                                <label>                                            Nome do campo                                        </label>                                                                <input                                            type="text"                                            name="fields[{{ $index }}][label]"                                            class="form-input"                                            value="{{ $field['label'] ?? '' }}"                                            placeholder="Ex: Tipo do óleo"                                        >                                                            </div>                                                            <div class="form-group field-col-type">                                                                <label>                                            Tipo                                        </label>                                                                <select                                            name="fields[{{ $index }}][field_type]"                                            class="form-input field-type-select"                                            onchange="toggleStockFields(this)"                                        >                                                                    <option                                                value="text"                                                @selected($fieldType == 'text')                                            >                                                Texto                                            </option>                                                                    <option                                                value="number"                                                @selected($fieldType == 'nu