h                                                                </select>                                                            </div>                                                            <div class="procedure-field-options stock-options-group">                                                                <label class="procedure-option-check">                                                                    <input                                                type="checkbox"                                                name="fields[{{ $index }}][has_quantity]"                                                value="1"                                                @checked(!empty($field['has_quantity']))                                            >                                                                    <span>                                                Solicitar quantidade usada                                            </span>                                                                </label>                                                            </div>                                                        </div>                                                    </div>                                                @empty                                                    <div                                class="procedure-fields-empty"                                id="procedure-fields-empty"                            >                                Nenhum campo adicional inserido.                            </div>                                                @endforelse                        </div>                </div>            </div>            <div class="procedure-side-card">                <div class="procedure-section compact">                    <div class="procedure-section-header">                        <h3