stener('DOMContentLoaded', () => {    const form =        document.getElementById('procedureForm');    const addFieldBtn =        document.getElementById('add-field-btn');    const wrapper =        document.getElementById('procedure-fields-wrapper');    const summaryList =        document.getElementById('procedureSummaryList');    const validityKm =        document.getElementById('validityKm');    const validityHours =        document.getElementById('validityHours');    const validityPeriod =        document.getElementById('validityPeriod');    const intervalKm =        document.getElementById('intervalKm');    const intervalHours =        document.getElementById('intervalHours');    const intervalDays =        document.getElementById('intervalDays');    const intervalKmError =        document.getElementById('intervalKmError');    const intervalHoursError =        document.getElementById('intervalHoursError');    const intervalDaysError =        document.getElementById('intervalDaysError');    let fieldIndex =        {{ count($existingFields ?? []) }};    function refreshIcons() {        if (window.lucide) {            lucide.createIcons();        }    }    function removeEmptyState() {        const empty =            document.getElementById('procedure-fields-empty');        if (empty) {            empty.remove();        }    }    function getNumber(input) {        return Number(input?.value || 0);    }    function clearValidation() {        [            intervalKm,            intervalHours,            intervalDays        ].forEach(input => {            if (input) {                input.classList.remove('input-invalid');            }        });        [            intervalKmError,            intervalHoursError,            intervalDaysError        ].forEach(error => {            if (error) {                error.style.display = 'none';            }        });    }    function addSummaryItem(type, label, value, suffix, icon) {        const item =            document.createElement('div');        item.className =            `summary-item summary-${type}`;        item.innerHTML = `            <span>                <i data-lucide="${icon}"></i>                ${label}            </span>            <strong>                ${value} ${suffix}            </strong>        `;        summaryList.appendChild(item);    }    function updateSummary() {        if (!summaryList) {            return;        }        summaryList.innerHTML = '';        let hasRule = false;        if (validityKm?.checked) {            hasRule = true;            addSummaryItem(                'km',                'Controle por KM',                getNumber(intervalKm).toLocaleString('pt-BR'),                'km',                'gauge'            );        }        if (validityHours?.checked) {            hasRule = true;            addSummaryItem(                'hours',                'Controle por Horas',                getNumber(intervalHours).toLocaleString('pt-BR'),                'h',                'clock'            );        }        if (validityPeriod?.checked) {            hasRule = true;            addSummaryItem(                'days',                'Controle por Período',                getNumber(intervalDays).toLocaleString('pt-BR'),                'dias',                'calendar-days'            );        }        if (!hasRule) {            const empty =                document.createElement('div');            empty.className =                'summary-empty';            empty.innerHTML = `                <i data-lucide="settings"></i>                <div>                    <strong>                        Sem validade automática                    </strong>                    <span>                        O procedimento será executado manualmente.                    </span>                </div>            `;            summaryList.appendChild(empty);        }        refreshIcons();    }    function validateValidityRules() {        clearValidation();        let valid = true;        if (            validityKm?.checked            &&            getNumber(intervalKm) <= 0        ) {            intervalKm.classList.add('input-invalid');            if (intervalKmError) {                intervalKmError.style.display = 'block';            }            valid = false;        }        if (            validityHours?.checked            &&            getNumber(intervalHours) <= 0        ) {            intervalHours.classList.add('input-invalid');            if (intervalHoursError) {                intervalHoursError.style.display = 'block';            }            valid = false;        }        if (            validityPeriod?.checked            &&            getNumber(intervalDays) <= 0        ) {            intervalDays.classList.add('input-invalid');            if (intervalDaysError) {                intervalDaysError.style.display = 'block';            }            valid = false;        }        return valid;    }    [        validityKm,        validityHours,        validityPeriod,        intervalKm,        intervalHours,        intervalDays    ].forEach(element => {        if (element) {            element.addEventListener(                'input',                updateSummary            );            element.addEventListener(                'change',                updateSummary            );        }    });    if (form) {        form.addEventListener('submit', (event) => {            if (!validateValidityRules()) {                event.preventDefault();                const firstInvalid =                    document.querySelector('.input-invalid');                if (firstInvalid) {                    firstInvalid.focus();                }                return false;            }        });    }    if (addFieldBtn && wrapper) {        addFieldBtn.addEventListener('click', () => {            removeEmptyState();            const row =                document.createElement('div');            row.className =                'procedure-field-row';            row.innerHTML = `                <div class="procedure-field-main-row">                    <div class="form-group field-col-name">                        <label>Nome do campo</label>                        <input                            type="text"                            name="fields[${fieldIndex}][label]"                            class="form-input"                            placeholder="Ex: Tipo do óleo"                        >                    </div>                    <div class="form-group field-col-type">                        <label>Tipo</label>                        <select                            name="fields[${fieldIndex}][field_type]"                            class="form-input field-type-select"                            onchange="toggleStockFields(this)"                        >                            <option value="text">Texto</option>                            <option value="number">Número</option>                            <option value="stock_item">Item de estoque</option>                        </select>                    </div>                    <div class="procedure-field-options field-col-required">                        <label class="procedure-option-check">                            <input                                type="checkbox"                                name="fields[${fieldIndex}][required]"                                value="1"                            >                            <span>                                Obrigatório                            </span>                        </label>                    </div>                    <div class="field-col-remove">                        <button                            type="button"                            class="field-remove-btn"                            onclick="this.closest('.procedure-field-row').remove()"                        >                            <i data-lucide="trash-2"></i>                        </button>                    </div>                </div>                <div class="procedure-field-stock-row">                    <div class="form-group stock-category-group">                        <label>Categoria de estoque</label>                        <select                            name="fields[${fieldIndex}][stock_category_id]"                            class="form-input"                        >                            <option value="">Selecione</option>                            @foreach($categories ?? [] as $category)                                <option value="{{ $category->id }}">                                    {{ $category->name }}                                </option>                            @endforeach                        </select>                    </div>                    <div class="procedure-field-options stock-options-group">                        <label class="procedure-option-check">                            <input                                type="checkbox"                                name="fields[${fieldIndex}][has_quantity]"                                value="1"                            >                            <span>                                Solicitar quantidade usada                            </span>                        </label>                    </div>                </div>            `;            wrapper.appendChild(row);            fieldIndex++;            refreshIcons();        });    }    document        .querySelectorAll('.field-type-select')        .forEach(select => {            window.toggleStockFields(select);        });    updateSummary();    refreshIcons();});</script>@endsection